import { GoogleGenAI } from "@google/genai";

export async function getGroundedLocationInfo(query: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça informações detalhadas e links oficiais do Google Maps sobre o seguinte local ou região em São Paulo: "${query}". Fale sobre sua importância histórica, curiosidades e o que o visitante pode esperar encontrar lá. Responda exclusivamente em português do Brasil.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: -23.5505,
              longitude: -46.6333
            }
          }
        }
      },
    });

    const text = response.text || "Informação não disponível no momento.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    return {
      text,
      links: chunks
        .filter((chunk: any) => chunk.maps)
        .map((chunk: any) => ({
          uri: chunk.maps.uri,
          title: chunk.maps.title || "Ver no Google Maps"
        }))
    };
  } catch (error) {
    console.error("Erro no Gemini Grounding:", error);
    return { text: "Erro ao carregar dados geográficos do local.", links: [] };
  }
}

